spec.root_selector:
(
  $dados := $map(
    $filter($, function($v) {
      $contains($v.path, "/properties/latestValue") and
      $contains($v.path, "DispX")
    }),
    function($v) {
      {
        "time": $substringBefore($v.time, "T"),
        "valor": $number($v.value.valor),
        "disp_num": $number(
          $substringBefore($substringAfter($v.path, "DispX"), "/")
        ),
        "path": $v.path
      }
    }
  );
  $datas := $sort($distinct($dados.time));
  $data_recente := $datas[-1];
  $data_antiga := $datas[0];
  $disps := $sort($distinct($dados.disp_num));
  $maxNum := $max($disps);
  $depthTop := (0 - $maxNum) * 0.5;
  $depthBottom := 0;
  $limAlerta := 15;
  $limAlarme := 20;
  $desvios := $map(
    $disps,
    function($d) {
      (
        $reg_recente := $filter($dados, function($r) { $r.time = $data_recente and $r.disp_num = $d })[0];
        $reg_antigo := $filter($dados, function($r) { $r.time = $data_antiga and $r.disp_num = $d })[0];
        {
          "disp_num": ($d - $maxNum) * 0.5,
          "valor": $number($reg_recente.valor) - $number($reg_antigo.valor),
          "path": $data_antiga & " → " & $data_recente
        }
      )
    }
  );
  $threshold_lines := [
    {"disp_num": $depthTop,    "valor": $limAlerta,  "path": "Alerta 1"},
    {"disp_num": $depthBottom, "valor": $limAlerta,  "path": "Alerta 1"},
    {"disp_num": $depthTop,    "valor": -$limAlerta, "path": "Alerta 2"},
    {"disp_num": $depthBottom, "valor": -$limAlerta, "path": "Alerta 2"},
    {"disp_num": $depthTop,    "valor": $limAlarme,  "path": "Alarme 1"},
    {"disp_num": $depthBottom, "valor": $limAlarme,  "path": "Alarme 1"},
    {"disp_num": $depthTop,    "valor": -$limAlarme, "path": "Alarme 2"},
    {"disp_num": $depthBottom, "valor": -$limAlarme, "path": "Alarme 2"}
  ];
  $append($desvios, $threshold_lines)
)

items[attributes.matricula ~> /^I/].{
  "matricula": attributes.matricula,
  "status": (
    $f := features;
    $active := $keys($f)[
      $contains($, "DispX") and
      $lookup($f, $).properties.latestValue != null
    ];
    $count($active) = 0 ? "UNAVAILABLE" : (
      $states := $active.($lookup($f, $).properties.state);
      $hasState := $count($states[$$ != null]) > 0;
      $hasState = false ? "UNAVAILABLE" :
        $count($states[$ = "ALARM"]) > 0 ? "ALARM" :
        $count($states[$ = "ALERT"]) > 0 ? "ALERT" : "OK"
    )
  ),
  "depths_in_alert": (
    $f := features;
    $join($keys($f)[
      $contains($, "DispX") and
      $lookup($f, $).properties.latestValue != null and
      $lookup($f, $).properties.state != "OK" and
      $lookup($f, $).properties.state != null
    ], ", ")
  )
}

